INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('2626e9e0-52c0-4309-beea-875f94400bb3', 'pq-ap-0001', 'apprentice', 'ohm-s-law-and-power', 'Ohm''s Law and Power', 'For Apprentice calculation question 1, during Ohm''s Law and Power scenario 1, which choice best aligns with NEC Article 100?', '{"A":"Apply Article 100 directly and document demand value 6.","B":"Ignore Article 100 and size from an unrelated chapter value 8.","C":"Delay code lookup until inspection and use estimate 10.","D":"Use manufacturer marketing language instead of NEC text 4."}'::jsonb, 'A', 'Question 1 is anchored to Ohm''s Law and Power scenario 1 and NEC Article 100. Choice A is preferred because it keeps the calculation and lookup sequence tied to the cited section rather than substituting unrelated assumptions. The distractors are weaker because they skip required code method steps or defer decisions that the exam expects you to make before installation.', 'Article 100', 'beginner', TRUE);
