INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65b31c7b-2df5-492d-bd83-aa1955ece60d', '17f22a38-65fd-490d-a693-7959af870f49', 1, 'paragraph', 'Learning objective', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2dba875a-bf77-40d4-8ef2-28bc1823eac6', '17f22a38-65fd-490d-a693-7959af870f49', 2, 'paragraph', 'Why this matters', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('078720f5-b41d-4983-90b6-dfce65715d1f', '17f22a38-65fd-490d-a693-7959af870f49', 3, 'paragraph', 'Core explanation', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('60dfc0bb-ecf3-4cf4-92aa-fc812c1f02db', '17f22a38-65fd-490d-a693-7959af870f49', 4, 'paragraph', 'Key concepts', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8c29f13c-e6e6-4e95-8ff5-38b87daf25c8', '17f22a38-65fd-490d-a693-7959af870f49', 5, 'paragraph', 'NEC / code relevance', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Use NEC Article 100 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. Use NEC Article 100 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2e85944b-e26a-465e-b080-091d8b07debd', '17f22a38-65fd-490d-a693-7959af870f49', 6, 'paragraph', 'Practical example', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Voltage, Current, Resistance, and Ohm''s Law focuses on understand voltage, current, resistance within Apprentice preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["Article 100"]}'::jsonb);
