INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f2f1eb6-7d31-4613-a524-2a30d250013b', '222483b9-7334-4522-bedb-2a293728377c', 2, 'paragraph', 'Why this matters', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('29d1a577-89ea-4fed-a73c-493d2fcb8fa5', '222483b9-7334-4522-bedb-2a293728377c', 3, 'paragraph', 'Core explanation', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["110.3(B)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65720862-c125-47b1-9c68-c27cf1eac38f', '222483b9-7334-4522-bedb-2a293728377c', 4, 'paragraph', 'Key concepts', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Electrical Hazard Recognition focuses on identify shock hazards within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["110.3(B)"]}'::jsonb);
