INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c3efc62b-33bf-4ab5-8e71-db3d4ab8b712', 'ef93ed13-2552-4843-a5c0-976c17863a40', 1, 'paragraph', 'Learning objective', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9335d80d-71c5-4d60-a4ce-acfa25ace89d', 'ef93ed13-2552-4843-a5c0-976c17863a40', 2, 'paragraph', 'Why this matters', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c33b813e-9b21-4bdc-962a-b9af73926031', 'ef93ed13-2552-4843-a5c0-976c17863a40', 3, 'paragraph', 'Core explanation', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('014df3f4-a491-40fb-9981-164ae74dba22', 'ef93ed13-2552-4843-a5c0-976c17863a40', 4, 'paragraph', 'Key concepts', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bd82d550-2744-41aa-9a50-60635072ce72', 'ef93ed13-2552-4843-a5c0-976c17863a40', 5, 'paragraph', 'NEC / code relevance', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Use NEC 90.1 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Use NEC 90.1 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c991619-4996-4767-8a04-36577b02c211', 'ef93ed13-2552-4843-a5c0-976c17863a40', 6, 'paragraph', 'Practical example', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('38925b99-5e0c-475c-95a4-5dff1eb749ab', 'ef93ed13-2552-4843-a5c0-976c17863a40', 7, 'paragraph', 'Common mistakes', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', 'Reading and Interpreting Code focuses on read code provisions correctly within Apprentice preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', '{"necReferences":["90.1"]}'::jsonb);
