INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c2ff1c1-0dec-4f8c-8c95-f013b9d6c8d9', '607f49a2-fe24-41b3-b22c-55439726f11f', 1, 'paragraph', 'Learning objective', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["250.24"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9a8fdc8e-3898-42e3-9d39-ff29894be28f', '607f49a2-fe24-41b3-b22c-55439726f11f', 2, 'paragraph', 'Why this matters', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["250.24"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d41e6956-e633-452a-b17e-ec51777a3a30', '607f49a2-fe24-41b3-b22c-55439726f11f', 3, 'paragraph', 'Core explanation', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["250.24"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1bcfb41d-423c-45b2-bd58-1a29fc31e6ec', '607f49a2-fe24-41b3-b22c-55439726f11f', 4, 'paragraph', 'Key concepts', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["250.24"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aef347cf-86be-4f28-ae51-5377cdb28637', '607f49a2-fe24-41b3-b22c-55439726f11f', 5, 'paragraph', 'NEC / code relevance', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Use NEC 250.24 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Residential Grounding focuses on understand service grounding within Apprentice preparation. Use NEC 250.24 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["250.24"]}'::jsonb);
