INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cecdcc78-a98e-4d9b-9ffb-ffe11f5cafdc', '38a5b1ac-e91d-491f-b720-75c70d567b19', 1, 'paragraph', 'Learning objective', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2b46ca22-27df-4f85-b54a-70605f3e224d', '38a5b1ac-e91d-491f-b720-75c70d567b19', 2, 'paragraph', 'Why this matters', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8cc8cc55-5c42-43ac-a1a8-59b27d54932c', '38a5b1ac-e91d-491f-b720-75c70d567b19', 3, 'paragraph', 'Core explanation', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5933dd55-a38f-4720-a9ce-896a74a2650c', '38a5b1ac-e91d-491f-b720-75c70d567b19', 4, 'paragraph', 'Key concepts', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('919012b6-6762-4967-8dd8-5fbcd17deec9', '38a5b1ac-e91d-491f-b720-75c70d567b19', 5, 'paragraph', 'NEC / code relevance', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Use NEC 90.3 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Use NEC 90.3 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0d811506-332c-43d9-bf3d-dc0222e4c967', '38a5b1ac-e91d-491f-b720-75c70d567b19', 6, 'paragraph', 'Practical example', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('428fd12f-4828-473c-8479-01c6b7ffd9cc', '38a5b1ac-e91d-491f-b720-75c70d567b19', 7, 'paragraph', 'Common mistakes', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', '{"necReferences":["90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('47dcf0ae-2469-40f6-a7ab-7bbc26ae06f1', '38a5b1ac-e91d-491f-b720-75c70d567b19', 8, 'paragraph', 'Exam insight', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. On exam day, read the stem for scope clues first, locate the governing section quickly, and eliminate distractors that violate sequence or cite the wrong article family.', 'Exception Hunting focuses on identify exceptions within Journeyman preparation. On exam day, read the stem for scope clues first, locate the governing section quickly, and eliminate distractors that violate sequence or cite the wrong article family.', '{"necReferences":["90.3"]}'::jsonb);
