INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('138d5b01-5e48-41eb-9d41-39683974912a', 'ed52a359-658b-433e-bba4-0680bf829ff9', 3, 'paragraph', 'Core explanation', 'Multi-Outlet Circuits focuses on understand multi-outlet design within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Multi-Outlet Circuits focuses on understand multi-outlet design within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["210.23"]}'::jsonb);
