INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9476fb13-c49a-4f50-b027-48e6316d6bad', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 1, 'paragraph', 'Learning objective', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9db58e47-057e-4bbc-bcfb-c8296a3df5f9', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 2, 'paragraph', 'Why this matters', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6eb75c5f-f033-4539-a404-cb433036e2e8', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 3, 'paragraph', 'Core explanation', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b96640c8-d14f-483a-bc26-b4d10705cd60', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 4, 'paragraph', 'Key concepts', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('92450c90-6a6a-43ba-ad48-f58a108fe746', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 5, 'paragraph', 'NEC / code relevance', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Use NEC 250.122 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Use NEC 250.122 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a1efb3df-ad40-4054-b33f-dc4e8a501788', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 6, 'paragraph', 'Practical example', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["250.122"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c423cad5-3590-4666-a7e8-0c1328746e1c', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 7, 'paragraph', 'Common mistakes', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', 'Equipment Grounding Sizing focuses on use sizing tables within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', '{"necReferences":["250.122"]}'::jsonb);
