INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('edd6aa8d-d6b2-46ea-bf76-8596d7b024d7', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 2, 'paragraph', 'Why this matters', 'Fault Currents focuses on calculate fault current within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Fault Currents focuses on calculate fault current within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["110.20"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('179c51e0-3621-44bc-9081-ececaa6b1330', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 3, 'paragraph', 'Core explanation', 'Fault Currents focuses on calculate fault current within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Fault Currents focuses on calculate fault current within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["110.20"]}'::jsonb);
