INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0423f8db-833b-4954-b95b-26fc415d3f09', '8d165d0d-1a39-4d7b-9019-067b449c6280', 1, 'paragraph', 'Learning objective', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('27141535-34c9-4b09-826f-45ca2b488ff3', '8d165d0d-1a39-4d7b-9019-067b449c6280', 2, 'paragraph', 'Why this matters', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f7433af-80b1-42e6-9323-a6b3d3db8f10', '8d165d0d-1a39-4d7b-9019-067b449c6280', 3, 'paragraph', 'Core explanation', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f3c7467-0e6c-49d7-985f-43b32e879e47', '8d165d0d-1a39-4d7b-9019-067b449c6280', 4, 'paragraph', 'Key concepts', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6216c7c8-d344-4cee-9e4c-12d8dedc85fe', '8d165d0d-1a39-4d7b-9019-067b449c6280', 5, 'paragraph', 'NEC / code relevance', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Use NEC 500-505 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Use NEC 500-505 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('14cff5f8-5716-43fd-8a2a-cbd0cb023857', '8d165d0d-1a39-4d7b-9019-067b449c6280', 6, 'paragraph', 'Practical example', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["500-505"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('20a05457-4cff-4840-90dd-2e91c6892768', '8d165d0d-1a39-4d7b-9019-067b449c6280', 7, 'paragraph', 'Common mistakes', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', 'Raceways in Hazardous Locations focuses on know requirements within Journeyman preparation. Frequent misses include selecting a table before confirming scope, skipping exception language, or applying a method from a different system class.', '{"necReferences":["500-505"]}'::jsonb);
