INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('be16cdad-5fbe-45a9-917b-1286c767dac1', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 1, 'paragraph', 'Learning objective', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. By the end of this lesson, you should be able to identify the governing rule path, interpret the requirement language, and explain how the rule affects installation and exam decisions.', '{"necReferences":["Article 700"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f7001d77-4c62-408e-8681-d9036f109b9e', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 2, 'paragraph', 'Why this matters', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["Article 700"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c2eedad-d83e-41ff-8c70-787707a7c254', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 3, 'paragraph', 'Core explanation', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["Article 700"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7fe96278-9070-4718-8b9f-9322402dfab1', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 4, 'paragraph', 'Key concepts', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["Article 700"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2a9c728a-6b8b-475c-bed1-e37c79aa4dc4', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 5, 'paragraph', 'NEC / code relevance', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Use NEC Article 700 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. Use NEC Article 700 as your anchor, then verify whether a more specific article modifies that baseline in the tested occupancy, equipment type, or system condition.', '{"necReferences":["Article 700"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5b98b74c-161f-42bd-b59b-df073fc33fac', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 6, 'paragraph', 'Practical example', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', 'Emergency Systems Article 700 focuses on know emergency rules within Master preparation. In a jobsite scenario, you would gather load data, select the correct table path, and document each assumption so a reviewer can trace every decision to a cited section.', '{"necReferences":["Article 700"]}'::jsonb);
