INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0e118caf-2520-48ce-b074-0b7ef516b14b', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 2, 'paragraph', 'Why this matters', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. This topic appears in both field inspections and timed exams because candidates must connect theory, code intent, and safe execution instead of memorizing isolated lines.', '{"necReferences":["Article 680"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df4fa75c-968b-41df-92a1-9f96c32efe88', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 3, 'paragraph', 'Core explanation', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. Start by identifying scope, then validate conductor or equipment constraints, then confirm overcurrent and grounding rules that interact with the same installation step.', '{"necReferences":["Article 680"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6416543c-6f7f-42ff-ae16-df7f03068717', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 4, 'paragraph', 'Key concepts', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', 'Pool and Spa Requirements focuses on know pool rules within Master preparation. Separate definitions, prescriptive requirements, and exceptions so you can move quickly from question stem to applicable section without mixing unrelated criteria.', '{"necReferences":["Article 680"]}'::jsonb);
